                if i != 0 {
                    return false;
                }
            }
            '/' | ':' | '*' | '?' | '"' | '<' | '>' | '|' => {
                return false;
            }
            _ if c.is_control() => {
                // Control characters (0-31) are not allowed
                return false;
            }
            _ => {}
        }
    }
    true
}

