pub fn run() -> Result<()> {
    let hwnd = create_window()?;

    // Show the window (optional, but good for testing)
    unsafe {
        use windows::Win32::UI::WindowsAndMessaging::{ShowWindow, SW_SHOWDEFAULT};
        ShowWindow(hwnd, SW_SHOWDEFAULT);
    }

    run_message_loop()?;
    Ok(())
}

