    struct ComGuard;
    impl Drop for ComGuard {
        fn drop(&mut self) {
            unsafe { CoUninitialize(); }
        }
    }
    let _guard = ComGuard;

    // Convert path to wide string
    let wide_path = wide_null(path.as_os_str());
    let pcwstr = PCWSTR(wide_path.as_ptr());

